import { Contributor, MatchResult, Church, Transaction } from '../../types';
import { normalizeString, parseDate, PLACEHOLDER_CHURCH } from '../utils/parsingUtils';

export const calculateNameSimilarity = (description: string, contributor: Contributor, ignoreKeywords: string[] = []): number => {
    const txNorm = normalizeString(description, ignoreKeywords);
    const contribNorm = contributor.normalizedName || normalizeString(contributor.name, ignoreKeywords);

    if (!txNorm || !contribNorm) return 0;

    const txTokens = txNorm.split(/\s+/).filter(t => t.length > 0);
    const contribTokens = contribNorm.split(/\s+/).filter(t => t.length > 0);

    if (txTokens.length === 0 || contribTokens.length === 0) return 0;

    const txSet = new Set(txTokens);
    const contribSet = new Set(contribTokens);
    const intersection = [...txSet].filter(w => contribSet.has(w)).length;
    return (2 * intersection) / (txSet.size + contribSet.size) * 100;
};

export const matchTransactions = (
    transactions: Transaction[],
    contributorFiles: any[],
    options: { similarityThreshold: number; dayTolerance: number; },
    learnedAssociations: any[],
    churches: Church[],
    customIgnoreKeywords: string[] = []
): MatchResult[] => {
    // Flatten contributors and assign internal IDs if missing
    const allContributors = contributorFiles.flatMap((file: any) => 
        file.contributors.map((c: any, idx: number) => ({ 
            ...c, 
            church: file.church,
            _internalId: `${file.church.id}-${idx}-${c.name}` // Unique key for tracking usage
        }))
    );

    const finalResults: MatchResult[] = [];
    const usedContributors = new Set<string>();

    transactions.forEach(tx => {
        // REMOVIDO FILTRO DE CONTROLE (SALDO/TOTAL) A PEDIDO DO USUÁRIO
        // if (NameResolver.isControlRow(tx.description)) return;

        const txDescNormalized = normalizeString(tx.description, customIgnoreKeywords);

        // 1. Check Learned Associations
        const learned = learnedAssociations.find((la: any) => la.normalizedDescription === txDescNormalized);
        if (learned) {
            const matchedContrib = allContributors.find((c: any) => 
                (normalizeString(c.name, customIgnoreKeywords) === learned.contributorNormalizedName) && 
                (c.church.id === learned.churchId)
            );

            // FIX: Aplicar validação de Tolerância de Data também para Associações Aprendidas
            // Isso garante que as configurações do modal sejam respeitadas mesmo para matches "conhecidos".
            let isDateValid = true;
            if (matchedContrib && options.dayTolerance !== undefined && matchedContrib.date && tx.date) {
                const tDate = parseDate(tx.date);
                const cDate = parseDate(matchedContrib.date);
                if (tDate && cDate) {
                    const diffDays = Math.ceil(Math.abs(tDate.getTime() - cDate.getTime()) / (1000 * 3600 * 24));
                    if (diffDays > options.dayTolerance) isDateValid = false;
                }
            }

            if (matchedContrib && isDateValid) {
                usedContributors.add(matchedContrib._internalId);
                finalResults.push({ 
                    transaction: tx, contributor: matchedContrib, status: 'IDENTIFICADO', 
                    church: matchedContrib.church, matchMethod: 'LEARNED', similarity: 100, 
                    contributorAmount: matchedContrib.amount,
                    contributionType: matchedContrib.contributionType || tx.contributionType
                });
                return;
            }
        }

        // 2. Check Automatic Match
        let bestMatch: any = null;
        let highestScore = 0;

        allContributors.forEach((contrib: any) => {
            if (options.dayTolerance !== undefined && contrib.date && tx.date) {
                const tDate = parseDate(tx.date);
                const cDate = parseDate(contrib.date);
                if (tDate && cDate) {
                    const diffDays = Math.ceil(Math.abs(tDate.getTime() - cDate.getTime()) / (1000 * 3600 * 24));
                    if (diffDays > options.dayTolerance) return;
                }
            }

            const score = calculateNameSimilarity(tx.description, contrib, customIgnoreKeywords);

            // Logica alterada: Captura o melhor score independente do threshold
            if (score > highestScore) {
                highestScore = score;
                bestMatch = contrib;
            }
        });

        if (bestMatch && highestScore >= options.similarityThreshold) {
            usedContributors.add(bestMatch._internalId);
            finalResults.push({ 
                transaction: tx, contributor: bestMatch, status: 'IDENTIFICADO', 
                church: bestMatch.church, similarity: highestScore, 
                matchMethod: 'AUTOMATIC', contributorAmount: bestMatch.amount,
                contributionType: bestMatch.contributionType || tx.contributionType
            });
        } else {
            // Se tiver um score razoável (ex: > 40%), anexa como sugestão
            const suggestion = (highestScore > 40 && bestMatch) ? bestMatch : undefined;

            finalResults.push({ 
                transaction: tx, 
                contributor: null, 
                status: 'NÃO IDENTIFICADO', 
                church: PLACEHOLDER_CHURCH,
                contributionType: tx.contributionType,
                suggestion: suggestion, // Novo campo
                similarity: highestScore // Score do best match
            });
        }
    });

    // 3. Add Unmatched Contributors (Ghost Transactions for Reporting)
    allContributors.forEach((contrib: any) => {
        if (!usedContributors.has(contrib._internalId)) {
            finalResults.push({
                transaction: {
                    id: `ghost-${contrib._internalId}-${Date.now()}`,
                    date: contrib.date || new Date().toISOString().split('T')[0],
                    description: contrib.name, // Nome do contribuinte vira descrição
                    amount: 0, // Valor zero pois não caiu no banco
                    cleanedDescription: contrib.name,
                    contributionType: contrib.contributionType,
                    originalAmount: "0.00"
                },
                contributor: contrib,
                status: 'PENDENTE', // Novo Status: Estava na lista, não no banco
                church: contrib.church,
                matchMethod: 'MANUAL', // Placeholder para indicar que veio da lista manual
                similarity: 0,
                contributorAmount: contrib.amount, // Valor esperado
                contributionType: contrib.contributionType
            });
        }
    });

    return finalResults;
};

export const groupResultsByChurch = (results: MatchResult[]): Record<string, MatchResult[]> => {
    const grouped: Record<string, MatchResult[]> = {};
    results.forEach(r => {
        const key = r.church?.id || 'unidentified';
        if (!grouped[key]) grouped[key] = [];
        grouped[key].push(r);
    });
    return grouped;
};

/**
 * ESPECIALISTA EM INTELIGÊNCIA MONETÁRIA (Core Engine v3)
 * Identifica a coluna correta por magnitude e limpa ruídos alfanuméricos com fidelidade absoluta.
 * 
 * ATUALIZAÇÃO (BR STRICT MODE + US SUPPORT):
 * Detecta automaticamente o formato (BR vs US) baseado na presença e ordem dos separadores.
 * Corrige bug onde 1,340 (milhar US) era lido como 1,34 (decimal BR).
 */
export class AmountResolver {
  /**
   * Identifica a coluna de valor correta entre múltiplas candidatas.
   * Regra Universal: Transações individuais costumam ter magnitude menor que saldos acumulados.
   */
  static identifyAmountColumn(rows: string[][], excludedIndices: number[] = []): number {
    const sample = rows.slice(0, 100);
    const candidateScores = new Map<number, { count: number, totalMagnitude: number }>();

    sample.forEach(row => {
      row.forEach((cell, index) => {
        if (excludedIndices.includes(index)) return;

        const val = this.simpleParse(cell);
        if (val !== null && val !== 0) {
          const stats = candidateScores.get(index) || { count: 0, totalMagnitude: 0 };
          stats.count++;
          stats.totalMagnitude += Math.abs(val);
          candidateScores.set(index, stats);
        }
      });
    });

    // Filtra apenas colunas que aparecem como valor em pelo menos 15% da amostra
    const validCandidates = Array.from(candidateScores.entries())
      .filter(([_, stats]) => stats.count > (sample.length * 0.15));

    if (validCandidates.length === 0) return -1;

    // Se houver mais de uma coluna numérica, a de MENOR magnitude média é a transação.
    // Saldos bancários são tipicamente ordens de magnitude maiores que as movimentações diárias.
    validCandidates.sort((a, b) => {
      const avgA = a[1].totalMagnitude / a[1].count;
      const avgB = b[1].totalMagnitude / b[1].count;
      return avgA - avgB;
    });

    return validCandidates[0][0];
  }

  /**
   * Limpa letras e símbolos, padronizando para string numérica pura (ponto decimal).
   * Suporta formatos BR (1.000,00) e US (1,000.00) inteligentemente.
   */
  static clean(rawAmount: any): string {
    // 1. Hardening: Proteção contra nulos/undefined
    if (rawAmount === null || rawAmount === undefined) return "0.00";

    // 2. Hardening: Conversão de tipos não-string
    let strAmount = String(rawAmount);
    if (!strAmount || strAmount.trim() === '') return "0.00";

    // 3. Normalização Inicial
    let cleaned = strAmount.trim().replace(/[R$\s]/g, '');

    // Proteção contra horários (Ex: 10:30)
    if (/\d{1,2}:\d{2}/.test(cleaned)) return "0.00";

    // Detecta sinal negativo (antes ou depois, ou parênteses, ou 'D' de Débito)
    const isNegative = 
        cleaned.includes('-') || 
        cleaned.includes('(') || 
        cleaned.toUpperCase().endsWith('D'); 

    // Remove tudo que não é número, ponto ou vírgula
    cleaned = cleaned.replace(/[^0-9.,]/g, '');

    // 4. LÓGICA DE NORMALIZAÇÃO INTELIGENTE (BR/US HÍBRIDO)
    const hasComma = cleaned.includes(',');
    const hasDot = cleaned.includes('.');

    if (hasComma && hasDot) {
        const lastDot = cleaned.lastIndexOf('.');
        const lastComma = cleaned.lastIndexOf(',');

        // Se o Ponto vem ANTES da Vírgula -> Padrão BR (1.000,00)
        if (lastDot < lastComma) {
            cleaned = cleaned.replace(/\./g, ''); 
            cleaned = cleaned.replace(',', '.');  
        } 
        // Se a Vírgula vem ANTES do Ponto -> Padrão US (1,000.00)
        else {
            cleaned = cleaned.replace(/,/g, ''); 
            // O ponto já é decimal, mantém
        }
    } 
    else if (hasComma) {
        const parts = cleaned.split(',');

        // Se houver múltiplas vírgulas (1,234,567), é milhar US
        if (parts.length > 2) {
            cleaned = cleaned.replace(/,/g, '');
        } 
        else if (parts.length === 2) {
            const decimalPart = parts[1];
            // HEURÍSTICA DE CONTEXTO: 
            // Se exatamente 3 dígitos após a vírgula (ex: 1,340), assume milhar US -> 1340
            // Isso corrige o bug de valores > 1000 vindos de CSV/Excel mal formatados
            if (decimalPart.length === 3) {
                cleaned = cleaned.replace(/,/g, '');
            } else {
                // Caso contrário (10,5 ou 10,50), assume decimal BR -> 10.5
                cleaned = cleaned.replace(',', '.');
            }
        }
    } 
    else if (hasDot) {
        const parts = cleaned.split('.');

        // Se houver múltiplos pontos (1.234.567), é milhar BR
        if (parts.length > 2) {
            cleaned = cleaned.replace(/\./g, '');
        } 
        else if (parts.length === 2) {
            const decimalPart = parts[1];
            // HEURÍSTICA DE CONTEXTO:
            // Se exatamente 3 dígitos após o ponto (ex: 1.000), assume milhar BR -> 1000
            if (decimalPart.length === 3) {
                cleaned = cleaned.replace(/\./g, '');
            }
            // Caso contrário (10.50), assume decimal US/Prog e mantém o ponto
        }
    }

    const val = parseFloat(cleaned);
    if (isNaN(val)) return "0.00";

    // Garante o sinal correto e fixação de casas decimais
    return (isNegative ? -Math.abs(val) : Math.abs(val)).toFixed(2);
  }

  /**
   * Versão ultra-leve para detecção de coluna (Usa a mesma lógica principal).
   */
  private static simpleParse(val: any): number | null {
    if (val === null || val === undefined) return null;
    const s = String(val).trim();
    if (s.length < 1) return null;
    if (s.includes(':')) return null;

    // Reutiliza a lógica robusta do clean, mas retorna float direto
    const cleanedStr = this.clean(s);
    const parsed = parseFloat(cleanedStr);

    return isNaN(parsed) ? null : parsed;
  }
}
